17	const PROCESSING_FEE = 5;
18	const BLOCK_SIZE = 3;
19	const COMPONENT_UNIT_PREMIUM = 25;
20	const COMPONENT_BLOCK_PREMIUM = 60;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const LOYALTY_RATE = 0.2;
23	const LOYALTY_MIN_YEARS = 2;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	
28	const COMPONENT_TYPES = ["rune", "moonstone"];
29	
30	const BASE_PREMIUMS: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: COMPONENT_UNIT_PREMIUM,
36	  moonstone: COMPONENT_UNIT_PREMIUM,
37	};
38	
39	const isComponent = (item: Item): boolean =>
40	  COMPONENT_TYPES.includes(item.type);
41	
42	const isMainItem = (item: Item): boolean => !isComponent(item);
43	
44	const unitPriceFor = (item: Item): number =>
45	  isComponent(item) ? COMPONENT_UNIT_PREMIUM : BASE_PREMIUMS[item.type] ?? 0;
46	
47	const sumOver = (items: Item[], valueOf: (item: Item) => number): number =>
48	  items.reduce((sum, item) => sum + valueOf(item), 0);
49	
50	const componentGroupPremium = (count: number): number =>
51	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
52	
53	const countByType = (items: Item[]): Map<string, number> =>
54	  items.reduce((counts, item) => {
55	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
56	    return counts;
57	  }, new Map<string, number>());
58	
59	const componentsBasePremium = (items: Item[]): number =>
60	  [...countByType(items.filter(isComponent)).values()].reduce(
61	    (sum, count) => sum + componentGroupPremium(count),
62	    0
63	  );
64	
65	const mainItemsBasePremium = (items: Item[]): number =>
66	  sumOver(items.filter(isMainItem), unitPriceFor);
67	
68	const totalBasePremium = (items: Item[]): number =>
69	  mainItemsBasePremium(items) + componentsBasePremium(items);
70	
71	const isHighlyEnchanted = (item: Item): boolean =>
72	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
73	
74	const itemSurchargeRate = (item: Item): number =>
75	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
76	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
77	
78	const itemSurcharges = (item: Item): number =>
79	  unitPriceFor(item) * itemSurchargeRate(item);
80	
81	const totalSurcharges = (items: Item[]): number =>
82	  sumOver(items, itemSurcharges);
83	
84	const firstInsuranceSurcharge = (policyBase: number): number =>
85	  policyBase * FIRST_INSURANCE_RATE;
86	
87	const isLoyal = (customer: Customer): boolean =>
88	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
89	
90	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
91	  isLoyal(customer) ? policyBase * LOYALTY_RATE : 0;
92	
93	export const quote = (input: QuoteInput): number => {
94	  const policyBase = totalBasePremium(input.items);
95	  const premiumBeforeFee =
96	    policyBase +
97	    totalSurcharges(input.items) +
98	    firstInsuranceSurcharge(policyBase) -
99	    loyaltyDiscount(policyBase, input.customer);
100	  return Math.ceil(premiumBeforeFee + PROCESSING_FEE);
101	};
102	
